SELECT members.name, members.membership_plan, payment_plans.plan_name, payment_plans.price
FROM members
JOIN payment_plans ON members.membership_plan = payment_plans.plan_name;

SELECT members.name
FROM members
WHERE members.memid IN (
  SELECT memid
  FROM payments
) AND members.memid IN (
  SELECT memid
  FROM bookings
);

SELECT DISTINCT m.memid, m.name, m.email
FROM members m
INNER JOIN bookings b ON m.memid = b.memid;

SELECT 
  (SELECT MAX(slots) FROM bookings) AS max_slots,
  (SELECT AVG(price) FROM payment_plans WHERE plan_name = 'annually') AS avg_annual_price;

SELECT AVG(
  (strftime('%Y', 'now') - strftime('%Y', date_of_birth)) - 
  (strftime('%m-%d', 'now') < strftime('%m-%d', date_of_birth))
) AS average_age
FROM members
WHERE memid IN (
  SELECT DISTINCT memid
  FROM bookings
);

SELECT SUM(amount) AS total_payments
FROM membership_payments
WHERE memid = 1;
